package sim

import (
	"fmt"
	"testing"

	"github.com/Mustafa4ngin/SwarmSync/pkg/gossip"
)

func TestNetworkSim_MerkleSyncPropagatesHigherVersionDelete(t *testing.T) {
	ns := NewNetworkSim(101)
	ns.AddNode("n1", 1)
	ns.AddNode("n2", 1)

	seedEntry(t, ns, []string{"n1", "n2"}, &gossip.StateEntry{
		Key:     "deleted",
		Value:   []byte("live"),
		Version: 1,
		NodeID:  "n1",
	})
	deleteVersion := ns.GetStore("n1").Delete("deleted")

	runMerkleRounds(ns, 5)

	requireDeletedEntry(t, ns.GetStore("n1"), "deleted", deleteVersion)
	requireDeletedEntry(t, ns.GetStore("n2"), "deleted", deleteVersion)
	if !ns.Converged() {
		t.Fatal("nodes should converge after higher-version delete")
	}
}

func TestNetworkSim_MerkleSyncDeleteWinsAtSameVersion(t *testing.T) {
	ns := NewNetworkSim(202)
	ns.AddNode("n1", 1)
	ns.AddNode("n2", 1)

	const version = 7
	seedEntry(t, ns, []string{"n1"}, &gossip.StateEntry{
		Key:     "same-version",
		Value:   []byte("live"),
		Version: version,
		NodeID:  "n1",
	})
	seedEntry(t, ns, []string{"n2"}, &gossip.StateEntry{
		Key:       "same-version",
		Version:   version,
		NodeID:    "n2",
		Tombstone: true,
	})

	runMerkleRounds(ns, 5)

	requireDeletedEntry(t, ns.GetStore("n1"), "same-version", version)
	requireDeletedEntry(t, ns.GetStore("n2"), "same-version", version)
	if !ns.Converged() {
		t.Fatal("nodes should converge when same-version tombstone meets live value")
	}
}

func TestNetworkSim_MerkleSyncBulkDeleteConvergence(t *testing.T) {
	ns := NewNetworkSim(303)
	nodeIDs := []string{"n0", "n1", "n2", "n3", "n4"}
	for _, nodeID := range nodeIDs {
		ns.AddNode(nodeID, 1)
	}

	const keyCount = 12
	for i := 0; i < keyCount; i++ {
		key := fmt.Sprintf("bulk-%02d", i)
		seedEntry(t, ns, nodeIDs, &gossip.StateEntry{
			Key:     key,
			Value:   []byte(fmt.Sprintf("value-%02d", i)),
			Version: uint64(i + 1),
			NodeID:  "n0",
		})
	}

	deleteVersions := make(map[string]uint64, keyCount)
	for i := 0; i < keyCount; i++ {
		key := fmt.Sprintf("bulk-%02d", i)
		deleteVersions[key] = ns.GetStore("n0").Delete(key)
	}

	for i := 0; i < 100; i++ {
		ns.RunMerkleSyncRound()
		if ns.Converged() {
			break
		}
	}
	if !ns.Converged() {
		t.Fatal("cluster should converge after bulk deletes")
	}
	for _, nodeID := range nodeIDs {
		store := ns.GetStore(nodeID)
		for key, version := range deleteVersions {
			requireDeletedEntry(t, store, key, version)
		}
	}
}

func runMerkleRounds(ns *NetworkSim, rounds int) {
	for i := 0; i < rounds; i++ {
		ns.RunMerkleSyncRound()
	}
}

func seedEntry(t *testing.T, ns *NetworkSim, nodeIDs []string, entry *gossip.StateEntry) {
	t.Helper()
	for _, nodeID := range nodeIDs {
		store := ns.GetStore(nodeID)
		if store == nil {
			t.Fatalf("missing store for node %s", nodeID)
		}
		if applied := store.Apply([]*gossip.StateEntry{entry}); applied != 1 {
			t.Fatalf("expected to seed %s on %s", entry.Key, nodeID)
		}
	}
}

func requireDeletedEntry(t *testing.T, store *gossip.StateStore, key string, version uint64) {
	t.Helper()
	if _, ok := store.Get(key); ok {
		t.Fatalf("%s should not be live", key)
	}
	entry, ok := store.GetEntry(key)
	if !ok {
		t.Fatalf("%s should have a tombstone", key)
	}
	if !entry.Tombstone {
		t.Fatalf("%s should be tombstoned", key)
	}
	if entry.Version != version {
		t.Fatalf("%s tombstone version = %d, want %d", key, entry.Version, version)
	}
}

