// Apply merges a set of remote entries into the local store.
// Entries with a higher version are accepted. If versions are equal, a
// tombstone wins over a live entry so deletes converge deterministically.
// Returns the number of entries that were actually applied.
func (s *StateStore) Apply(entries []*StateEntry) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	applied := 0
	for _, remote := range entries {
		local, ok := s.entries[remote.Key]
		if !ok || shouldApplyRemote(local, remote) {
			cp := *remote
			cp.Value = copyBytes(remote.Value)
			s.entries[remote.Key] = &cp
			if cp.Version > s.version {
				s.version = cp.Version
			}
			applied++
		}
	}
	if applied > 0 {
		s.hashDirty = true
	}
	return applied
}

func shouldApplyRemote(local, remote *StateEntry) bool {
	if remote.Version > local.Version {
		return true
	}
	if remote.Version < local.Version {
		return false
	}
	return remote.Tombstone && !local.Tombstone
}

